<template>
    <div class="main-content">
        <el-dialog title="审核" :visible.sync="keyanxiangmuYesnoTypesVisible">
            <el-form :model="form">
                <input type="hidden" v-model="form.id">
                <el-form-item label="审核" >
                    <el-select v-model="form.keyanxiangmuYesnoTypes" placeholder="请选择申请状态">
                        <el-option label="同意" value="2"></el-option>
                        <el-option label="拒绝" value="3"></el-option>
                    </el-select>
                </el-form-item>
                <el-form-item label="审核意见">
                    <el-input type="textarea" v-model="form.keyanxiangmuYesnoText" placeholder="审核意见"></el-input>
                </el-form-item>
            </el-form>
            <div slot="footer" class="dialog-footer">
                <el-button @click="keyanxiangmuYesnoTypesVisible = false">取 消</el-button>
                <el-button type="primary" @click="keyanxiangmuYesnoTypesShenhe">审 核</el-button>
            </div>
        </el-dialog>
        <!-- 条件查询 -->
        <div v-if="showFlag">
            <el-form :inline="true" :model="searchForm" class="form-content">
                <el-row :gutter="20" class="slt" :style="{justifyContent:contents.searchBoxPosition=='1'?'flex-start':contents.searchBoxPosition=='2'?'center':'flex-end'}">
                                 
                     <el-form-item :label="contents.inputTitle == 1 ? '项目来源' : ''">
                         <el-input prefix-icon="el-icon-search" v-model="searchForm.keyanxiangmuLaiyuan" placeholder="项目来源" clearable></el-input>
                     </el-form-item>
         
                     <el-form-item :label="contents.inputTitle == 1 ? '科研项目名称' : ''">
                         <el-input prefix-icon="el-icon-search" v-model="searchForm.keyanxiangmuName" placeholder="科研项目名称" clearable></el-input>
                     </el-form-item>
                                                                         
                     <el-form-item :label="contents.inputTitle == 1 ? '申请状态' : ''">
                        <el-select v-model="searchForm.keyanxiangmuYesnoTypes" placeholder="请选择申请状态">
                            <el-option label="=-请选择-=" value=""></el-option>
                            <el-option
                               v-for="(item,index) in keyanxiangmuYesnoTypesSelectSearch"
                               v-bind:key="index"
                               :label="item.indexName"
                               :value="item.codeIndex">
                            <!--lable是要展示的名称-->
                            <!--value是值-->
                            </el-option>
                        </el-select>
                     </el-form-item>

                                                
                                                             
                    <el-form-item :label="contents.inputTitle == 1 ? '科研人员编号' : ''">
                        <el-input prefix-icon="el-icon-search" v-model="searchForm.yonghuUuidNumber" placeholder="科研人员编号" clearable></el-input>
                    </el-form-item>
                     
                    <el-form-item :label="contents.inputTitle == 1 ? '科研人员姓名' : ''">
                        <el-input prefix-icon="el-icon-search" v-model="searchForm.yonghuName" placeholder="科研人员姓名" clearable></el-input>
                    </el-form-item>
                                                                                                                         
                     
                     
                    

                    <el-form-item>
                        <el-button type="success" @click="search()">查询<i class="el-icon-search el-icon--right"/></el-button>
                    </el-form-item>
                </el-row>
                <el-row class="ad" :style="{justifyContent:contents.btnAdAllBoxPosition=='1'?'flex-start':contents.btnAdAllBoxPosition=='2'?'center':'flex-end'}">
                    <el-form-item>
                        <el-button
                                v-if="isAuth('keyanxiangmu','新增')"
                                type="success"
                                icon="el-icon-plus"
                                @click="addOrUpdateHandler()"
                        >新增</el-button>
                        &nbsp;
                        <el-button
                                v-if="isAuth('keyanxiangmu','删除')"
                                :disabled="dataListSelections.length <= 0"
                                type="danger"
                                icon="el-icon-delete"
                                @click="deleteHandler()"
                        >删除</el-button>
                        &nbsp;
                        <el-button
                                v-if="isAuth('keyanxiangmu','报表')"
                                type="success"
                                icon="el-icon-pie-chart"
                                @click="chartDialog()"
                        >报表</el-button>
                        &nbsp;
                        <a style="text-decoration:none" class="el-button el-button--success"
                           v-if="isAuth('keyanxiangmu','导入导出')"
                           icon="el-icon-download"
                           href="http://localhost:8080/gaoxiaokeyanxinxi/upload/keyanxiangmuMuBan.xls"
                        >批量导入科研项目数据模板</a>
                        &nbsp;
                        <el-upload
                                v-if="isAuth('keyanxiangmu','导入导出')"
                                style="display: inline-block"
                                :action="getActionUrl"
                                :on-success="keyanxiangmuUploadSuccess"
                                :on-error="keyanxiangmuUploadError"
                                :show-file-list = false>
                            <el-button
                                    v-if="isAuth('keyanxiangmu','导入导出')"
                                    type="success"
                                    icon="el-icon-upload2"
                            >批量导入科研项目数据</el-button>
                        </el-upload>
                        &nbsp;
                        <!-- 导出excel -->
                        <download-excel v-if="isAuth('keyanxiangmu','导入导出')" style="display: inline-block" class = "export-excel-wrapper" :data = "dataList" :fields = "json_fields" name = "keyanxiangmu.xls">
                            <!-- 导出excel -->
                            <el-button
                                    type="success"
                                    icon="el-icon-download"
                            >导出</el-button>
                        </download-excel>
                        &nbsp;
                    </el-form-item>
                </el-row>
            </el-form>
            <div class="table-content">
                <el-table class="tables" :size="contents.tableSize" :show-header="contents.tableShowHeader"
                          :header-row-style="headerRowStyle" :header-cell-style="headerCellStyle"
                          :border="contents.tableBorder"
                          :fit="contents.tableFit"
                          :stripe="contents.tableStripe"
                          :row-style="rowStyle"
                          :cell-style="cellStyle"
                          :style="{width: '100%',fontSize:contents.tableContentFontSize,color:contents.tableContentFontColor}"
                          v-if="isAuth('keyanxiangmu','查看')"
                          :data="dataList"
                          v-loading="dataListLoading"
                          @selection-change="selectionChangeHandler">
                    <el-table-column  v-if="contents.tableSelection"
                                      type="selection"
                                      header-align="center"
                                      align="center"
                                      width="50">
                    </el-table-column>
                    <el-table-column label="索引" v-if="contents.tableIndex" type="index" width="50" />
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="yonghuUuidNumber"
                                      header-align="center"
                                      label="科研人员编号">
                        <template slot-scope="scope">
                            {{scope.row.yonghuUuidNumber}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="yonghuName"
                                      header-align="center"
                                      label="科研人员姓名">
                        <template slot-scope="scope">
                            {{scope.row.yonghuName}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="yonghuPhone"
                                      header-align="center"
                                      label="科研人员手机号">
                        <template slot-scope="scope">
                            {{scope.row.yonghuPhone}}
                        </template>
                    </el-table-column>
                    <el-table-column :sortable="contents.tableSortable" :align="contents.tableAlign" prop="yonghuPhoto"
                               header-align="center"
                               width="200"
                               label="科研人员头像">
                        <template slot-scope="scope">
                            <div v-if="scope.row.yonghuPhoto">
                                <img :src="$base.url+scope.row.yonghuPhoto" width="100" height="100">
                            </div>
                            <div v-else>无图片</div>
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="keyanxiangmuUuidNumber"
                                   header-align="center"
                                   label="科研项目编号">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuUuidNumber}}
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="keyanxiangmuLaiyuan"
                                   header-align="center"
                                   label="项目来源">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuLaiyuan}}
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="keyanxiangmuName"
                                   header-align="center"
                                   label="科研项目名称">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuName}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="dengjiTypes"
                                      header-align="center"
                                      label="项目等级">
                        <template slot-scope="scope">
                            {{scope.row.dengjiValue}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="xuekeTypes"
                                      header-align="center"
                                      label="学科">
                        <template slot-scope="scope">
                            {{scope.row.xuekeValue}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="keyanxiangmuHuafei"
                                      header-align="center"
                                      label="项目预算(元)">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuHuafei}}
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="kaishiTime"
                                   header-align="center"
                                   label="项目开始时间">
                        <template slot-scope="scope">
                            {{scope.row.kaishiTime}}
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="jieshuTime"
                                   header-align="center"
                                   label="项目结束时间">
                        <template slot-scope="scope">
                            {{scope.row.jieshuTime}}
                        </template>
                    </el-table-column>
                    <el-table-column :sortable="contents.tableSortable" :align="contents.tableAlign" prop="keyanxiangmuFile"
                                     header-align="center"
                                     width="200"
                                     label="项目申报书">
                        <template slot-scope="scope">
                            <div v-if="scope.row.keyanxiangmuFile">
                                <a type="text" style="text-decoration:none" class="el-button" :href="$base.url+scope.row.keyanxiangmuFile">下载</a>
                            </div>
                            <div v-else>无文件</div>
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="insertTime"
                                   header-align="center"
                                   label="申请时间">
                        <template slot-scope="scope">
                            {{scope.row.insertTime}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="keyanxiangmuYesnoTypes"
                                      header-align="center"
                                      label="申请状态">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuYesnoValue}}
                        </template>
                    </el-table-column>
                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                      prop="keyanxiangmuYesnoText"
                                      header-align="center"
                                      label="审核意见">
                        <template slot-scope="scope">
                            <span v-if="scope.row.keyanxiangmuYesnoText != null &&scope.row.keyanxiangmuYesnoText.length>10">
                                {{scope.row.keyanxiangmuYesnoText.slice(0,10)}}...
                            </span>
                            <span v-else>
                                {{scope.row.keyanxiangmuYesnoText}}
                            </span>
                        </template>
                    </el-table-column>

                    <el-table-column  :sortable="contents.tableSortable" :align="contents.tableAlign"
                                   prop="keyanxiangmuShenheTime"
                                   header-align="center"
                                   label="审核时间">
                        <template slot-scope="scope">
                            {{scope.row.keyanxiangmuShenheTime}}
                        </template>
                    </el-table-column>
                    <el-table-column :sortable="contents.tableSortable" :align="contents.tableAlign" prop="keyanxiangmuLixiangFile"
                                     header-align="center"
                                     width="200"
                                     label="项目立项文件">
                        <template slot-scope="scope">
                            <div v-if="scope.row.keyanxiangmuLixiangFile">
                                <a type="text" style="text-decoration:none" class="el-button" :href="$base.url+scope.row.keyanxiangmuLixiangFile">下载</a>
                            </div>
                            <div v-else>无文件</div>
                        </template>
                    </el-table-column>
                    <el-table-column :sortable="contents.tableSortable" :align="contents.tableAlign" prop="keyanxiangmuJiexiangFile"
                                     header-align="center"
                                     width="200"
                                     label="项目结项书">
                        <template slot-scope="scope">
                            <div v-if="scope.row.keyanxiangmuJiexiangFile">
                                <a type="text" style="text-decoration:none" class="el-button" :href="$base.url+scope.row.keyanxiangmuJiexiangFile">下载</a>
                            </div>
                            <div v-else>无文件</div>
                        </template>
                    </el-table-column>
                    <el-table-column :sortable="contents.tableSortable" :align="contents.tableAlign" prop="keyanxiangmuJiexiangwenjianFile"
                                     header-align="center"
                                     width="200"
                                     label="项目结项文件">
                        <template slot-scope="scope">
                            <div v-if="scope.row.keyanxiangmuJiexiangwenjianFile">
                                <a type="text" style="text-decoration:none" class="el-button" :href="$base.url+scope.row.keyanxiangmuJiexiangwenjianFile">下载</a>
                            </div>
                            <div v-else>无文件</div>
                        </template>
                    </el-table-column>

                    <el-table-column width="300" :align="contents.tableAlign"
                                     header-align="center"
                                     label="操作">
                        <template slot-scope="scope">
                            <el-button v-if="isAuth('keyanxiangmu','查看')" type="success" icon="el-icon-tickets" size="mini" @click="addOrUpdateHandler(scope.row.id,'info')">详情</el-button>
                            <el-button v-if="isAuth('keyanxiangmu','修改')" type="primary" icon="el-icon-edit" size="mini" @click="addOrUpdateHandler(scope.row.id)">修改</el-button>
                            <el-button v-if="isAuth('keyanxiangmu','删除')" type="danger" icon="el-icon-delete" size="mini" @click="deleteHandler(scope.row.id)">删除</el-button>
                            <el-button v-if="isAuth('keyanxiangmu','审核') && scope.row.keyanxiangmuYesnoTypes == 1 " type="primary" icon="el-icon-thumb" size="mini" @click="openYesnoTypes(scope.row.id)">审核</el-button>
                            <el-button v-if="sessionTable=='yonghu' && scope.row.keyanxiangmuYesnoTypes==2
                            &&(scope.row.keyanxiangmuLixiangFile == null || scope.row.keyanxiangmuLixiangFile=='')
                            &&(scope.row.keyanxiangmuJiexiangFile == null || scope.row.keyanxiangmuJiexiangFile=='')
                            &&(scope.row.keyanxiangmuJiexiangwenjianFile == null || scope.row.keyanxiangmuJiexiangwenjianFile=='')
                            " type="primary" icon="el-icon-edit" size="mini" @click="addOrUpdateHandler(scope.row.id)">上传科研成果</el-button>

                        </template>
                    </el-table-column>
                </el-table>
                <el-pagination
                        clsss="pages"
                        :layout="layouts"
                        @size-change="sizeChangeHandle"
                        @current-change="currentChangeHandle"
                        :current-page="pageIndex"
                        :page-sizes="[10, 20, 50, 100]"
                        :page-size="Number(contents.pageEachNum)"
                        :total="totalPage"
                        :small="contents.pageStyle"
                        class="pagination-content"
                        :background="contents.pageBtnBG"
                        :style="{textAlign:contents.pagePosition==1?'left':contents.pagePosition==2?'center':'right'}"
                ></el-pagination>
            </div>
        </div>
        <!-- 添加/修改页面  将父组件的search方法传递给子组件-->
        <add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>



        <el-dialog title="统计报表" :visible.sync="chartVisiable" width="80%">

            <div id="statistic" style="width:100%;height:600px;"></div>
            <span slot="footer" class="dialog-footer">
				<el-button @click="chartVisiable = false">关闭</el-button>
			</span>
        </el-dialog>

    </div>
</template>
<script>
    import AddOrUpdate from "./add-or-update";
    import styleJs from "../../../utils/style.js";
    import utilsJs from "../../../utils/utils.js";

    export default {
        data() {
        return {
            searchForm: {
                key: ""
            },
            sessionTable : "",//登录账户所在表名
            role : "",//权限
            userId:"",//当前登录人的id
    //级联表下拉框搜索条件
              zhiwuTypesSelectSearch : [],
              zhichengTypesSelectSearch : [],
              xueliTypesSelectSearch : [],
    //当前表下拉框搜索条件
              keyanxiangmuYesnoTypesSelectSearch : [],
            form:{
                id : null,
                yonghuId : null,
                keyanxiangmuUuidNumber : null,
                keyanxiangmuLaiyuan : null,
                keyanxiangmuName : null,
                dengjiTypes : null,
                xuekeTypes : null,
                keyanxiangmuHuafei : null,
                kaishiTime : null,
                jieshuTime : null,
                keyanxiangmuFile : null,
                keyanxiangmuContent : null,
                insertTime : null,
                keyanxiangmuYesnoTypes : null,
                keyanxiangmuYesnoText : null,
                keyanxiangmuShenheTime : null,
                keyanxiangmuLixiangFile : null,
                keyanxiangmuJiexiangFile : null,
                keyanxiangmuJiexiangwenjianFile : null,
                createTime : null,
            },
            dataList: [],
            pageIndex: 1,
            pageSize: 10,
            totalPage: 0,
            dataListLoading: false,
            dataListSelections: [],
            showFlag: true,
            sfshVisiable: false,
            shForm: {},
            chartVisiable: false,
            echartsDate: new Date(),//echarts的时间查询字段
            addOrUpdateFlag:false,
            contents:null,
            layouts: '',

            keyanxiangmuYesnoTypesVisible : false,

            //导出excel
            json_fields: {
                //级联表字段
                     '科研人员编号': 'yonghuUuidNumber',
                     '科研人员姓名': 'yonghuName',
                     '科研人员手机号': 'yonghuPhone',
                     '科研人员身份证号': 'yonghuIdNumber',
                     '科研人员头像': 'yonghuPhoto',
                     '年龄': 'age',
                     '电子邮箱': 'yonghuEmail',
                     '职务': 'zhiwuTypes',
                     '职称': 'zhichengTypes',
                     '学历': 'xueliTypes',
                //本表字段
                     '科研项目编号': "keyanxiangmuUuidNumber",
                     '项目来源': "keyanxiangmuLaiyuan",
                     '科研项目名称': "keyanxiangmuName",
                     '项目等级': "dengjiValue",
                     '学科': "xuekeValue",
                     '项目预算(元)': "keyanxiangmuHuafei",
                     '项目开始时间': "kaishiTime",
                     '项目结束时间': "jieshuTime",
                     '项目申报书': "keyanxiangmuFile",
                     '申请时间': "insertTime",
                     '申请状态': "keyanxiangmuYesnoValue",
                     '审核意见': "keyanxiangmuYesnoText",
                     '审核时间': "keyanxiangmuShenheTime",
                     '项目立项文件': "keyanxiangmuLixiangFile",
                     '项目结项书': "keyanxiangmuJiexiangFile",
                     '项目结项文件': "keyanxiangmuJiexiangwenjianFile",
            },

            };
        },
        created() {
            this.contents = styleJs.listStyle();
            this.init();
            this.getDataList();
            this.contentStyleChange()
        },
        mounted() {
            //获取当前登录科研人员的信息
            this.sessionTable = this.$storage.get("sessionTable");
            this.role = this.$storage.get("role");
            this.userId = this.$storage.get("userId");

        },
        filters: {
            htmlfilter: function (val) {
                return val.replace(/<[^>]*>/g).replace(/undefined/g,'');
            }
        },
        components: {
            AddOrUpdate,
        },
        computed: {
            getActionUrl: function() {
                return `/`+this.$base.name+`/file/upload`;
            }
        },
        methods: {
            chartDialog() {
                let _this = this;
                //饼状图
                _this.chartVisiable = true;
                this.$nextTick(()=>{
                    var statistic = this.$echarts.init(document.getElementById("statistic"),'macarons');
                    let params = {
                        tableName: "keyanxiangmu",
                        groupColumn: "xueke_types",
                    }
                    this.$http({
                        url: "newSelectGroupCount",
                        method: "get",
                        params: params
                    }).then(({data}) => {
                        if (data && data.code === 0) {
                            let res = data.data;
                            let xAxis = [];
                            let yAxis = [];
                            let pArray = []
                            var option = {};
                            for(let i=0;i<res.length;i++){
                                xAxis.push(res[i].name);
                                yAxis.push(res[i].value);
                                pArray.push({
                                    value: res[i].value,
                                    name: res[i].name
                                })
                                option = {
                                    title: {
                                        text: '科研项目学科分布统计',
                                        left: 'center'
                                    },
                                    tooltip: {
                                        trigger: 'item',
                                        formatter: '{b} : {c} ({d}%)'
                                    },
                                    series: [
                                        {
                                            type: 'pie',
                                            radius: '55%',
                                            center: ['50%', '60%'],
                                            data: pArray,
                                            emphasis: {
                                                itemStyle: {
                                                    shadowBlur: 10,
                                                    shadowOffsetX: 0,
                                                    shadowColor: 'rgba(0, 0, 0, 0.5)'
                                                }
                                            }
                                        }
                                    ]
                                };
                            }
                                statistic.setOption(option,true);
                                window.onresize = function() {
                                    statistic.resize();
                                };
                        }
                    });
                })
            },
            contentStyleChange() {
                this.contentSearchStyleChange()
                this.contentBtnAdAllStyleChange()
                this.contentSearchBtnStyleChange()
                this.contentTableBtnStyleChange()
                this.contentPageStyleChange()
            },
            contentSearchStyleChange() {
                this.$nextTick(() => {
                    document.querySelectorAll('.form-content .slt .el-input__inner').forEach(el => {
                        let textAlign = 'left'
                        if(this.contents.inputFontPosition == 2)
                            textAlign = 'center'
                            if (this.contents.inputFontPosition == 3) textAlign = 'right'
                                el.style.textAlign = textAlign
                            el.style.height = this.contents.inputHeight
                            el.style.lineHeight = this.contents.inputHeight
                            el.style.color = this.contents.inputFontColor
                            el.style.fontSize = this.contents.inputFontSize
                            el.style.borderWidth = this.contents.inputBorderWidth
                            el.style.borderStyle = this.contents.inputBorderStyle
                            el.style.borderColor = this.contents.inputBorderColor
                            el.style.borderRadius = this.contents.inputBorderRadius
                            el.style.backgroundColor = this.contents.inputBgColor
                    })
